import java.net.InetAddress;
import java.net.UnknownHostException;

import org.json.JSONObject;

import android.content.Context;
import android.util.Log;

import com.maxmind.geoip2.DatabaseReader;
import com.maxmind.geoip2.model.CityResponse;

public class LocationService {

    public static String getCountry(Context context) {
        try {
            InetAddress ip = InetAddress.getByName("8.8.8.8");
            DatabaseReader reader = new DatabaseReader.Builder(context.getAssets()).build();
            CityResponse response = reader.city(ip);
            return response.getCountry().getName();
        } catch (UnknownHostException e) {
            Log.e("LocationService", "Unknown host exception", e);
            return null;
        }
    }
}
```
This code uses the MaxMind GeoIP2 library to estimate a user's country based on their IP address.
